sql:
SELECT RF_PLI_001_CarteraInv.Fec_Pro, RF_PLI_001_CarteraInv.Cod_Emp, RF_PLI_001_CarteraInv.Moneda, RF_PLI_001_CarteraInv.Cod_Pro, RF_PLI_001_CarteraInv.Cod_Sub_Pro, RF_PLI_001_CarteraInv.Nemotecnico, RF_PLI_001_CarteraInv.Instrumento, RF_PLI_001_CarteraInv.VP_Cap_Amort, RF_PLI_001_CarteraInv.VP_Int_Total, RF_PLI_001_CarteraInv.Dias_Vcto
FROM RF_PLI_001_CarteraInv
WHERE RF_PLI_001_CarteraInv.Moneda='CLP' AND (RF_PLI_001_CarteraInv.Instrumento='BBC');

SELECT RF_PLI_037_CarteraBBC_CLP.Fec_Pro, RF_PLI_037_CarteraBBC_CLP.Moneda, RF_PLI_037_CarteraBBC_CLP.Cod_Pro, SUM(RF_PLI_037_CarteraBBC_CLP.VP_Cap_Amort+RF_PLI_037_CarteraBBC_CLP.VP_Int_Total) AS VP_Flujo
FROM RF_PLI_037_CarteraBBC_CLP
GROUP BY RF_PLI_037_CarteraBBC_CLP.Fec_Pro, RF_PLI_037_CarteraBBC_CLP.Moneda, RF_PLI_037_CarteraBBC_CLP.Cod_Pro;

SELECT RF_base_Completa_Hist.Fec_Pro, RF_base_Completa_Hist.Cod_Emp, RF_base_Completa_Hist.Moneda, IIf(RF_base_Completa_Hist.Cod_Pro='INVERSIONES FINANCIERAS FONDOS MUTUOS' Or RF_base_Completa_Hist.Cod_Pro='INVERSIONES FINANCIERAS FONDOS MUTUOS DERIVADOS','Inversion Financiera Privado',RF_base_Completa_Hist.Cod_Pro) AS Cod_Pro, RF_base_Completa_Hist.Cod_Sub_Pro, RF_base_Completa_Hist.Nemotecnico, Left(RF_base_Completa_Hist.Nemotecnico,3) AS Instrumento, RF_base_Completa_Hist.VP_Cap_Amort, RF_base_Completa_Hist.VP_Int_Total, RF_base_Completa_Hist.Dias_Vcto
FROM RF_Fecha_Proceso_Carteras INNER JOIN RF_base_Completa_Hist ON RF_Fecha_Proceso_Carteras.Fecha = RF_base_Completa_Hist.Fec_Pro
WHERE Left(RF_base_Completa_Hist.Nemotecnico,3)<>'LCH' And (Left(RF_base_Completa_Hist.Cod_Pro,20)='Inversion Financiera' Or Left(RF_base_Completa_Hist.Cod_Pro,23)='INVERSIONES FINANCIERAS') And (Right(RF_base_Completa_Hist.Cod_Sub_Pro,4)='Disp' Or Right(RF_base_Completa_Hist.Cod_Sub_Pro,8)='Disp_Liq' Or Right(RF_base_Completa_Hist.Cod_Sub_Pro,6)='MUTUOS') And RF_base_Completa_Hist.Clasificacion_Contable<>"HTM";
